import 'dart:convert';

import '../shared/navivox_gateway_json.dart';
import 'navivox_gateway_event.dart';

/// Decodes one raw WebSocket event payload into the typed gateway event model.
///
/// The gateway stream can deliver already-decoded objects in tests/adapters or
/// JSON strings from real sockets. Invalid payloads are normalized to the same
/// typed error event so clients do not duplicate wire-shape checks.
NavivoxGatewayEvent navivoxGatewayEventFromWire(Object? event) {
  final object = navivoxGatewayObjectFromWireEvent(event);
  if (object == null) return navivoxInvalidGatewayEvent();
  return NavivoxGatewayEvent.fromJson(object);
}

/// Converts one loose WebSocket payload into a decoded event object.
///
/// This intentionally returns `null` for malformed JSON, non-object JSON, and
/// non-map adapter payloads so callers can preserve the gateway client's
/// bad-response event contract without leaking parser exceptions.
Map<String, Object?>? navivoxGatewayObjectFromWireEvent(Object? event) {
  final decoded = _navivoxDecodedWireEvent(event);
  return navivoxGatewayOptionalObjectFromJson(decoded);
}

NavivoxGatewayEvent navivoxInvalidGatewayEvent() {
  return const NavivoxGatewayEvent(
    type: 'error',
    code: 'bad_response',
    message: 'Invalid gateway event',
  );
}

Object? _navivoxDecodedWireEvent(Object? event) {
  if (event is! String) return event;
  try {
    return jsonDecode(event);
  } on FormatException {
    return null;
  }
}

import 'navivox_gateway_event_decoder.dart';

void main() {
  invalidJsonStringBecomesBadResponseEvent();
  nonObjectJsonStringBecomesBadResponseEvent();
  decodedObjectEventStillParses();
  decodedMapWithNonStringKeyBecomesBadResponseEvent();
}

void invalidJsonStringBecomesBadResponseEvent() {
  final event = navivoxGatewayEventFromWire('{not json');

  _expect(event.isError, 'invalid JSON string should decode to error event');
  _expect(
    event.code == 'bad_response',
    'invalid JSON code should be bad_response',
  );
  _expect(
    event.message == 'Invalid gateway event',
    'invalid JSON message should describe invalid gateway event',
  );
}

void nonObjectJsonStringBecomesBadResponseEvent() {
  final event = navivoxGatewayEventFromWire('[1, 2, 3]');

  _expect(event.isError, 'non-object JSON string should decode to error event');
  _expect(
    event.code == 'bad_response',
    'non-object JSON code should be bad_response',
  );
}

void decodedObjectEventStillParses() {
  final event = navivoxGatewayEventFromWire({
    'type': 'message',
    'text': 'hello',
  });

  _expect(event.type == 'message', 'decoded map event type should parse');
  _expect(event.text == 'hello', 'decoded map event text should parse');
}

void decodedMapWithNonStringKeyBecomesBadResponseEvent() {
  final event = navivoxGatewayEventFromWire({1: 'message', 'text': 'hello'});

  _expect(
    event.isError,
    'adapter maps with non-string keys should decode to error event',
  );
  _expect(
    event.code == 'bad_response',
    'adapter maps with non-string keys should be bad_response',
  );
}

void _expect(bool condition, String message) {
  if (!condition) throw StateError(message);
}

import '../../protocol/navivox_json.dart'
    show navivoxMapFieldFromJson, navivoxOptionalStringFromJson;
import '../shared/navivox_gateway_json.dart';

/// Typed event received from the Navivox gateway WebSocket stream.
class NavivoxGatewayEvent {
  const NavivoxGatewayEvent({
    required this.type,
    this.requestId,
    this.sessionId,
    this.text,
    this.code,
    this.message,
    this.toolName,
    this.toolCallId,
    this.status,
    this.safetyId,
    this.approvalId,
    this.severity,
    this.risk,
    this.runRecordReference,
    this.metadata = const {},
    this.contact,
  });

  factory NavivoxGatewayEvent.fromJson(Map<String, Object?> json) {
    final metadata = navivoxMapFieldFromJson(json, 'metadata');
    final contact = navivoxGatewayOptionalObjectFromJson(json['contact']);
    return NavivoxGatewayEvent(
      type: navivoxGatewayRawStringField(json, 'type'),
      requestId: navivoxGatewayOptionalRawStringField(json, 'request_id'),
      sessionId: navivoxGatewayOptionalRawStringField(json, 'session_id'),
      text: navivoxGatewayOptionalRawStringField(json, 'text'),
      code: navivoxGatewayOptionalRawStringField(json, 'code'),
      message: navivoxGatewayOptionalRawStringField(json, 'message'),
      toolName: navivoxGatewayOptionalRawStringField(json, 'tool_name'),
      toolCallId: navivoxGatewayOptionalRawStringField(json, 'tool_call_id'),
      status: navivoxGatewayOptionalRawStringField(json, 'status'),
      safetyId: navivoxGatewayOptionalRawStringField(json, 'safety_id'),
      approvalId: navivoxGatewayOptionalRawStringField(json, 'approval_id'),
      severity: navivoxGatewayOptionalRawStringField(json, 'severity'),
      risk: navivoxGatewayOptionalRawStringField(json, 'risk'),
      runRecordReference: _runRecordReferenceFromJson(json, metadata),
      metadata: metadata,
      contact: contact,
    );
  }

  final String type;
  final String? requestId;
  final String? sessionId;
  final String? text;
  final String? code;
  final String? message;
  final String? toolName;
  final String? toolCallId;
  final String? status;
  final String? safetyId;
  final String? approvalId;
  final String? severity;
  final String? risk;
  final String? runRecordReference;
  final Map<String, Object?> metadata;
  final Map<String, Object?>? contact;

  bool get isError => type == 'error';
}

String? _runRecordReferenceFromJson(
  Map<String, Object?> json,
  Map<String, Object?> metadata,
) {
  return navivoxOptionalStringFromJson(json['run_record_ref']) ??
      navivoxOptionalStringFromJson(json['run_record_reference']) ??
      navivoxOptionalStringFromJson(metadata['run_record_ref']) ??
      navivoxOptionalStringFromJson(metadata['run_record_reference']);
}

export 'navivox_voice_status.dart';

import 'navivox_voice_status.dart';

class NavivoxVoiceRun {
  const NavivoxVoiceRun({
    required this.id,
    required this.serverId,
    required this.profileId,
    required this.status,
    required this.transcriptSource,
    required this.ttsStatus,
    required this.createdAt,
    required this.updatedAt,
    this.sessionId,
    this.requestId,
    this.transcript,
    this.duration,
    this.confidence,
    this.reason,
    this.retentionPolicy = 'transcript_only',
  });

  factory NavivoxVoiceRun.recording({
    required String id,
    required String serverId,
    required String profileId,
    required DateTime createdAt,
  }) {
    return NavivoxVoiceRun(
      id: id,
      serverId: serverId,
      profileId: profileId,
      status: NavivoxVoiceRunStatus.recording,
      transcriptSource: NavivoxTranscriptSource.device,
      ttsStatus: NavivoxTtsStatus.unavailable,
      createdAt: createdAt,
      updatedAt: createdAt,
    );
  }

  final String id;
  final String serverId;
  final String profileId;
  final String? sessionId;
  final String? requestId;
  final NavivoxVoiceRunStatus status;
  final NavivoxTranscriptSource transcriptSource;
  final NavivoxTtsStatus ttsStatus;
  final String? transcript;
  final Duration? duration;
  final double? confidence;
  final String? reason;
  final String retentionPolicy;
  final DateTime createdAt;
  final DateTime updatedAt;

  bool get isTerminal => navivoxVoiceRunStatusIsTerminal(status);

  NavivoxVoiceRun withDeviceTranscript({
    required String transcript,
    required Duration duration,
    required double confidence,
    required DateTime updatedAt,
  }) {
    return copyWith(
      status: NavivoxVoiceRunStatus.pendingSend,
      transcriptSource: NavivoxTranscriptSource.device,
      transcript: transcript,
      duration: duration,
      confidence: confidence,
      updatedAt: updatedAt,
    );
  }

  NavivoxVoiceRun markSubmitted({
    required String requestId,
    String? sessionId,
  }) {
    return NavivoxVoiceRun(
      id: id,
      serverId: serverId,
      profileId: profileId,
      sessionId: sessionId,
      requestId: requestId,
      status: NavivoxVoiceRunStatus.submitted,
      transcriptSource: transcriptSource,
      ttsStatus: ttsStatus,
      transcript: transcript,
      duration: duration,
      confidence: confidence,
      reason: null,
      retentionPolicy: retentionPolicy,
      createdAt: createdAt,
      updatedAt: updatedAt,
    );
  }

  NavivoxVoiceRun markCompleted() {
    return copyWith(status: NavivoxVoiceRunStatus.completed);
  }

  NavivoxVoiceRun markCancelled(String reason) {
    return copyWith(status: NavivoxVoiceRunStatus.cancelled, reason: reason);
  }

  NavivoxVoiceRun markFailed(String reason) {
    return copyWith(status: NavivoxVoiceRunStatus.failed, reason: reason);
  }

  NavivoxVoiceRun copyWith({
    String? sessionId,
    String? requestId,
    NavivoxVoiceRunStatus? status,
    NavivoxTranscriptSource? transcriptSource,
    NavivoxTtsStatus? ttsStatus,
    String? transcript,
    Duration? duration,
    double? confidence,
    String? reason,
    String? retentionPolicy,
    DateTime? updatedAt,
  }) {
    return NavivoxVoiceRun(
      id: id,
      serverId: serverId,
      profileId: profileId,
      sessionId: sessionId ?? this.sessionId,
      requestId: requestId ?? this.requestId,
      status: status ?? this.status,
      transcriptSource: transcriptSource ?? this.transcriptSource,
      ttsStatus: ttsStatus ?? this.ttsStatus,
      transcript: transcript ?? this.transcript,
      duration: duration ?? this.duration,
      confidence: confidence ?? this.confidence,
      reason: reason ?? this.reason,
      retentionPolicy: retentionPolicy ?? this.retentionPolicy,
      createdAt: createdAt,
      updatedAt: updatedAt ?? this.updatedAt,
    );
  }
}

import 'navivox_voice_run.dart';

void main() {
  markSubmittedDoesNotCarryStaleFailureReason();
  markSubmittedUsesCurrentNullableSession();
}

void markSubmittedDoesNotCarryStaleFailureReason() {
  final failedRun = _pendingRun().markFailed('Gateway is not connected.');

  final submitted = failedRun.markSubmitted(
    requestId: 'request-2',
    sessionId: 'session-2',
  );

  _expect(
    submitted.status == NavivoxVoiceRunStatus.submitted,
    'run should be submitted after retry transition',
  );
  _expect(
    submitted.reason == null,
    'submitted retry should not keep a stale terminal failure reason',
  );
}

void markSubmittedUsesCurrentNullableSession() {
  final submittedRun = _pendingRun().markSubmitted(
    requestId: 'request-1',
    sessionId: 'session-1',
  );

  final resubmitted = submittedRun.markSubmitted(
    requestId: 'request-2',
    sessionId: null,
  );

  _expect(
    resubmitted.requestId == 'request-2',
    'resubmission should replace the request id',
  );
  _expect(
    resubmitted.sessionId == null,
    'resubmission should reflect the current absent session id',
  );
}

NavivoxVoiceRun _pendingRun() {
  return NavivoxVoiceRun.recording(
    id: 'voice-1',
    serverId: 'server-1',
    profileId: 'profile-1',
    createdAt: DateTime.utc(2026),
  ).withDeviceTranscript(
    transcript: 'hello',
    duration: const Duration(milliseconds: 500),
    confidence: 0.9,
    updatedAt: DateTime.utc(2026, 1, 1, 0, 0, 1),
  );
}

void _expect(bool condition, String message) {
  if (!condition) throw StateError(message);
}

import '../../../../core/channel/navivox_channel.dart';
import '../../../../core/protocol/navivox_voice_run.dart';
