import '../../../gateway/messages/navivox_gateway_event.dart';
import '../../../protocol/navivox_event.dart';
import '../../../protocol/navivox_json.dart';
import '../../contracts/navivox_message_scope.dart';

/// Resolves the server/profile scope for gateway transcript events.
///
/// Gateway events may carry scope directly in metadata, or indirectly through
/// the request/tool-call message they update. Keeping the lookup policy here
/// keeps assistant, tool, safety, and approval event handling aligned.
NavivoxMessageScope navivoxGatewayMessageScopeFromEvent({
  required NavivoxGatewayEvent event,
  required Map<String, NavivoxChatMessage> messages,
}) {
  final metadataServerId = navivoxOptionalStringFromJson(
    event.metadata['server_id'],
  );
  final metadataProfileId = navivoxOptionalStringFromJson(
    event.metadata['profile_id'],
  );
  if (metadataServerId != null && metadataProfileId != null) {
    return navivoxMessageScope(
      serverId: metadataServerId,
      profileId: metadataProfileId,
    );
  }

  final requestMessage = event.requestId == null
      ? null
      : messages[event.requestId!];
  final requestScope = _messageScope(requestMessage);
  if (requestScope != null) return requestScope;

  final toolMessage = event.toolCallId == null
      ? null
      : messages[event.toolCallId!];
  final toolScope = _messageScope(toolMessage);
  if (toolScope != null) return toolScope;

  return navivoxUnscopedMessage;
}

NavivoxMessageScope? _messageScope(NavivoxChatMessage? message) {
  if (message?.profileContactKey == null) return null;
  return navivoxMessageScope(
    serverId: message!.serverId,
    profileId: message.profileId,
  );
}

import '../../../gateway/navivox_gateway_protocol.dart';
import '../../../protocol/navivox_event.dart';
import '../../contracts/navivox_message_scope.dart';

/// Builds assistant transcript messages from gateway events.
///
/// Assistant delta and final-message events share the same message id, scope,
/// and run-record merge contract. Keeping this mapping here prevents the two
/// event paths from drifting as the transcript payload evolves.
String navivoxGatewayAssistantMessageId({
  required NavivoxGatewayEvent event,
  required String Function() fallbackRequestId,
}) {
  final requestId = event.requestId ?? fallbackRequestId();
  return 'assistant-$requestId';
}

NavivoxChatMessage navivoxGatewayAssistantTextMessage({
  required String id,
  required NavivoxGatewayEvent event,
  required NavivoxChatMessage? existing,
  required DateTime createdAt,
  required NavivoxMessageScope scope,
  required bool appendText,
}) {
  final incomingText = event.text ?? '';
  final text = appendText
      ? '${existing?.text ?? ''}$incomingText'
      : incomingText;
  final messageScope = navivoxMessageScopeWithFallback(
    serverId: existing?.serverId,
    profileId: existing?.profileId,
    fallback: scope,
  );
  return NavivoxChatMessage(
    id: id,
    author: existing?.author ?? NavivoxMessageAuthor.assistant,
    kind: existing?.kind ?? NavivoxMessageKind.text,
    createdAt: existing?.createdAt ?? createdAt,
    text: text,
    runRecordReference:
        event.runRecordReference ?? existing?.runRecordReference,
    serverId: messageScope.serverId,
    profileId: messageScope.profileId,
  );
}

import '../../../gateway/navivox_gateway_protocol.dart';
import '../../../protocol/navivox_event.dart';
import '../../contracts/navivox_message_scope.dart';
import '../approvals/gateway_approval_notice.dart';
import '../codecs/gateway_tool_artifact_codec.dart';

/// Builds durable tool-call cards from gateway events.
///
/// Progress updates and approval-required events both mutate the same tool-call
/// card. Centralizing that merge contract keeps status, approval, artifacts,
/// run-record references, and profile scope aligned.
NavivoxChatMessage navivoxGatewayToolCallMessage({
  required String id,
  required NavivoxGatewayEvent event,
  required String status,
  required NavivoxChatMessage? priorMessage,
  required DateTime createdAt,
  required NavivoxMessageScope scope,
}) {
  final prior = priorMessage?.toolCall;
  final messageScope = navivoxMessageScopeWithFallback(
    serverId: priorMessage?.serverId,
    profileId: priorMessage?.profileId,
    fallback: scope,
  );
  return NavivoxChatMessage(
    id: id,
    author: NavivoxMessageAuthor.assistant,
    kind: NavivoxMessageKind.toolCall,
    createdAt: priorMessage?.createdAt ?? createdAt,
    toolCall: NavivoxToolCall(
      name: event.toolName ?? prior?.name ?? 'tool',
      status: status,
      summary: navivoxBoundedGatewayToolText(
        event.message ?? event.text ?? prior?.summary ?? '',
      ),
      approval: prior?.approval,
      artifacts: navivoxGatewayToolArtifacts(
        metadata: event.metadata,
        toolCallId: id,
        prior: prior?.artifacts ?? const [],
      ),
    ),
    runRecordReference:
        event.runRecordReference ?? priorMessage?.runRecordReference,
    serverId: messageScope.serverId,
    profileId: messageScope.profileId,
  );
}

NavivoxChatMessage? navivoxGatewayToolApprovalMessage({
  required String id,
  required NavivoxGatewayEvent event,
  required NavivoxChatMessage? priorMessage,
  required NavivoxGatewayApprovalNotice notice,
  required DateTime createdAt,
  required NavivoxMessageScope scope,
}) {
  final priorTool = priorMessage?.toolCall;
  if (priorTool == null) return null;
  final messageScope = navivoxMessageScopeWithFallback(
    serverId: priorMessage?.serverId,
    profileId: priorMessage?.profileId,
    fallback: scope,
  );
  return NavivoxChatMessage(
    id: id,
    author: NavivoxMessageAuthor.assistant,
    kind: NavivoxMessageKind.toolCall,
    createdAt: priorMessage?.createdAt ?? createdAt,
    toolCall: priorTool.copyWith(
      approval: navivoxGatewayToolApproval(notice: notice),
    ),
    runRecordReference:
        event.runRecordReference ?? priorMessage?.runRecordReference,
    serverId: messageScope.serverId,
    profileId: messageScope.profileId,
  );
}

List<NavivoxToolArtifact> navivoxGatewayToolArtifacts({
  required Map<String, Object?> metadata,
  required String toolCallId,
  required List<NavivoxToolArtifact> prior,
}) {
  final parsed = navivoxToolArtifactsFromGatewayMetadata(
    metadata,
    toolCallId: toolCallId,
  );
  if (parsed.isEmpty) return prior;
  final byId = {for (final artifact in prior) artifact.id: artifact};
  for (final artifact in parsed) {
    byId[artifact.id] = artifact;
  }
  return byId.values.toList(growable: false);
}

import '../../../gateway/navivox_gateway_protocol.dart';
