import '../turns/gateway_turn_metadata_policy.dart';

/// Builds local user transcript messages for turns sent to the gateway.
///
/// Text and voice submissions both create a user-visible transcript entry before
/// sending the shared start_turn frame. Centralizing the message construction
/// keeps profile scope and voice payload handling aligned across input modes.
NavivoxChatMessage navivoxGatewayUserTurnMessage({
  required String id,
  required String text,
  required DateTime createdAt,
  required NavivoxMessageScope scope,
  NavivoxVoiceMessage? voice,
}) {
  return NavivoxChatMessage(
    id: id,
    author: NavivoxMessageAuthor.user,
    kind: voice == null ? NavivoxMessageKind.text : NavivoxMessageKind.voice,
    createdAt: createdAt,
    text: text,
    serverId: scope.serverId,
    profileId: scope.profileId,
    voice: voice,
  );
}

/// Bundles the local user transcript entry with the gateway start-turn frame.
///
/// Text and voice turns share this submission contract: create the durable local
/// message with the active profile scope, then send the same start_turn frame to
/// the gateway. Keeping both artifacts together prevents the two input paths
/// from diverging when the turn wire contract changes.
({NavivoxChatMessage message, String frame}) navivoxGatewayUserTurnSubmission({
  required String requestId,
  required String? sessionId,
  required String text,
  required DateTime createdAt,
  required NavivoxProfileContact? profile,
  required NavivoxProfileRoutingSelection? routing,
  NavivoxVoiceMessage? voice,
}) {
  return (
    message: navivoxGatewayUserTurnMessage(
      id: requestId,
      text: text,
      createdAt: createdAt,
      scope: navivoxMessageScope(
        serverId: profile?.serverId,
        profileId: profile?.profileId,
      ),
      voice: voice,
    ),
    frame: navivoxGatewayStartTurnFrame(
      requestId: requestId,
      sessionId: sessionId,
      text: text,
      profile: profile,
      routing: routing,
    ),
  );
}

import '../identity/navivox_profile_contact_key.dart';
import '../voice/navivox_voice_status.dart';

enum NavivoxMessageKind {
  text,
  toolCall,
  voice,
  safetyWarning,
  approvalRequest,
}

enum NavivoxMessageAuthor { user, assistant, system }

class NavivoxChatMessage {
  const NavivoxChatMessage({
    required this.id,
    required this.author,
    required this.kind,
    required this.createdAt,
    this.text,
    this.toolCall,
    this.voice,
    this.safetyNotice,
    this.runRecordReference,
    this.serverId,
    this.profileId,
  });

  final String id;
  final NavivoxMessageAuthor author;
  final NavivoxMessageKind kind;
  final DateTime createdAt;
  final String? text;
  final NavivoxToolCall? toolCall;
  final NavivoxVoiceMessage? voice;
  final NavivoxSafetyNotice? safetyNotice;
  final String? runRecordReference;
  final String? serverId;
  final String? profileId;

  String? get profileContactKey => navivoxProfileContactKeyFromNullable(
    serverId: serverId,
    profileId: profileId,
  );
}

class NavivoxToolCall {
  const NavivoxToolCall({
    required this.name,
    required this.status,
    required this.summary,
    this.approval,
    this.artifacts = const [],
  });

  final String name;
  final String status;
  final String summary;
  final NavivoxToolApproval? approval;
  final List<NavivoxToolArtifact> artifacts;

  NavivoxToolCall copyWith({
    String? name,
    String? status,
    String? summary,
    NavivoxToolApproval? approval,
    List<NavivoxToolArtifact>? artifacts,
  }) {
    return NavivoxToolCall(
      name: name ?? this.name,
      status: status ?? this.status,
      summary: summary ?? this.summary,
      approval: approval ?? this.approval,
      artifacts: artifacts ?? this.artifacts,
    );
  }
}

class NavivoxToolApproval {
  const NavivoxToolApproval({
    required this.id,
    required this.status,
    required this.prompt,
    this.risk,
  });

  final String id;
  final String status;
  final String prompt;
  final String? risk;
}

class NavivoxToolArtifact {
  const NavivoxToolArtifact({
    required this.id,
    required this.kind,
    required this.title,
    this.summary,
    this.ref,
  });

  final String id;
  final String kind;
  final String title;
  final String? summary;
  final String? ref;
}

class NavivoxSafetyNotice {
  const NavivoxSafetyNotice({
    required this.id,
    required this.message,
    this.severity,
    this.risk,
    this.approvalId,
    this.toolCallId,
  });

  final String id;
  final String message;
  final String? severity;
  final String? risk;
  final String? approvalId;
  final String? toolCallId;
}

class NavivoxVoiceMessage {
  const NavivoxVoiceMessage({
    required this.duration,
    required this.transcript,
    required this.confidence,
    this.voiceRunId,
    this.status,
  });

  final String? voiceRunId;
  final Duration duration;
  final String transcript;
  final double confidence;
  final NavivoxVoiceRunStatus? status;
