import '../../../protocol/navivox_event.dart';
import '../../../protocol/navivox_json.dart';

/// Gateway metadata decoder for transcript tool artifacts.
///
/// The gateway may send either structured artifact entries or a legacy flat
/// artifact payload. When neither is present, non-sensitive metadata is folded
/// into a bounded synthetic artifact so tool-call cards can still expose useful
/// context without leaking secrets.
List<NavivoxToolArtifact> navivoxToolArtifactsFromGatewayMetadata(
  Map<String, Object?> metadata, {
  required String toolCallId,
}) {
  if (metadata.isEmpty) return const [];
  final artifacts = <NavivoxToolArtifact>[];
  final artifactList = metadata['artifacts'];
  if (artifactList is List) {
    for (final artifact in artifactList.whereType<Map>()) {
      final parsed = _toolArtifactFromMap(Map<String, Object?>.from(artifact));
      if (parsed != null) artifacts.add(parsed);
    }
  }
  final single = _toolArtifactFromFlatMetadata(metadata);
  if (single != null) artifacts.add(single);
  if (artifacts.isNotEmpty) return artifacts;
  return [
    NavivoxToolArtifact(
      id: 'metadata-$toolCallId',
      kind: 'metadata',
      title: 'Tool metadata',
      summary: navivoxBoundedGatewayToolText(_safeMetadataSummary(metadata)),
    ),
  ];
}

String navivoxBoundedGatewayToolText(String text) {
  final trimmed = text.trim();
  if (trimmed.length <= 240) return trimmed;
  return '${trimmed.substring(0, 237)}...';
}

NavivoxToolArtifact? _toolArtifactFromMap(Map<String, Object?> json) {
  final id = navivoxOptionalStringFromJson(json['id']);
  final kind = navivoxOptionalStringFromJson(json['kind']);
  final title = navivoxOptionalStringFromJson(json['title']);
  if (id == null || kind == null || title == null) return null;
  return NavivoxToolArtifact(
    id: id,
    kind: kind,
    title: title,
    summary: navivoxOptionalStringFromJson(json['summary']),
    ref: navivoxOptionalStringFromJson(json['ref']),
  );
}

NavivoxToolArtifact? _toolArtifactFromFlatMetadata(
  Map<String, Object?> metadata,
) {
  final id = navivoxOptionalStringFromJson(metadata['artifact_id']);
  final kind = navivoxOptionalStringFromJson(metadata['artifact_kind']);
  final title = navivoxOptionalStringFromJson(metadata['artifact_title']);
  if (id == null || kind == null || title == null) return null;
  return NavivoxToolArtifact(
    id: id,
    kind: kind,
    title: title,
    summary: navivoxOptionalStringFromJson(metadata['artifact_summary']),
    ref: navivoxOptionalStringFromJson(metadata['artifact_ref']),
  );
}

String _safeMetadataSummary(Map<String, Object?> metadata) {
  final parts = <String>[];
  for (final entry in metadata.entries) {
    if (_isSensitiveMetadataKey(entry.key)) continue;
    parts.add('${entry.key}: ${_safeMetadataValue(entry.value)}');
  }
  return parts.isEmpty ? 'Metadata unavailable' : parts.join('; ');
}

String _safeMetadataValue(Object? value) {
  if (value is Map) return '[object]';
  if (value is List) return '[list]';
  return value?.toString() ?? '';
}

bool _isSensitiveMetadataKey(String key) {
  final lower = key.toLowerCase();
  return lower.contains('token') ||
      lower.contains('secret') ||
      lower.contains('password') ||
      lower.contains('api_key') ||
      lower.contains('apikey');
}

/// Shared coercion helpers for Navivox wire-protocol JSON payloads.
///
/// These helpers intentionally accept loose `Object?` values because gateway and
/// memory endpoints can be decoded from typed maps, platform channels, or JSON
/// maps with dynamic keys.
String navivoxStringFromJson(Object? value, {required String fallback}) {
  final text = value?.toString().trim();
  if (text == null || text.isEmpty) return fallback;
  return text;
}

String? navivoxOptionalStringFromJson(Object? value) {
  final text = value?.toString().trim();
  if (text == null || text.isEmpty) return null;
  return text;
}

/// Returns a trimmed string only when [value] is already a literal string.
String? navivoxOptionalLiteralStringFromJson(Object? value) {
  if (value is! String) return null;
  final text = value.trim();
  return text.isEmpty ? null : text;
}

int navivoxIntFromJson(Object? value) {
  if (value is int) return value;
  if (value is num) return value.toInt();
  return int.tryParse(value?.toString() ?? '') ?? 0;
}

double? navivoxDoubleFromJson(Object? value) {
  if (value is double) return value;
  if (value is num) return value.toDouble();
  return double.tryParse(value?.toString() ?? '');
}

bool navivoxBoolFromJson(Object? value, {bool fallback = false}) {
  if (value is bool) return value;
  final text = value?.toString().trim().toLowerCase();
  if (text == 'true' || text == '1' || text == 'yes') return true;
  if (text == 'false' || text == '0' || text == 'no') return false;
  return fallback;
}

/// Returns only literal bool values or `true`/`false` string tokens.
///
/// Use this for protocol flags whose existing contract intentionally does not
/// accept broader truthy aliases such as `1` or `yes`.
bool navivoxStrictBoolFromJson(Object? value, {bool fallback = false}) {
  if (value is bool) return value;
  final text = value?.toString().trim().toLowerCase();
  if (text == 'true') return true;
  if (text == 'false') return false;
  return fallback;
}

Map<String, Object?> navivoxMapFromJson(Object? value) {
  if (value is! Map) return const {};
  return Map<String, Object?>.from(value);
}

Map<String, Object?> navivoxMapFieldFromJson(
  Map<String, Object?> json,
  String key,
) {
  return navivoxMapFromJson(json[key]);
}

List<Object?> navivoxListFromJson(Object? value) {
  if (value is! List) return const [];
  return value.cast<Object?>();
}

/// Returns map entries from a loose wire list, ignoring non-map items.
List<Map<String, Object?>> navivoxMapListFromJson(Object? value) {
  return navivoxListFromJson(
    value,
  ).whereType<Map>().map(navivoxMapFromJson).toList(growable: false);
}

List<Object?> navivoxListFieldFromJson(Map<String, Object?> json, String key) {
  return navivoxListFromJson(json[key]);
}

List<String> navivoxStringListFromJson(Object? value) {
  if (value is! List) return const [];
  return navivoxTrimmedStringList(value);
}

String navivoxStringFieldFromJson(Map<String, Object?> json, String key) {
  return navivoxStringFromJson(json[key], fallback: '');
}

/// Selects a typed enum/value object by matching its wire value.
///
/// The wire token uses the same non-empty trimmed string semantics as other
/// Navivox protocol fields and falls back when the value is blank or unknown.
T navivoxValueFromWire<T>({
  required Object? value,
  required Iterable<T> values,
  required String Function(T value) wireValue,
  required T fallback,
}) {
  final text = navivoxOptionalStringFromJson(value);
  if (text == null) return fallback;
  for (final candidate in values) {
    if (wireValue(candidate) == text) return candidate;
  }
  return fallback;
}

/// Returns the first non-empty literal string field whose key matches [names].
///
/// The lookup first honors exact keys, then falls back to a compatibility match
/// that ignores underscores and case so wire payloads can use either
/// `snake_case` or `camelCase` aliases without each parser reimplementing that
/// policy. Non-string values are intentionally ignored to preserve strict wire
/// semantics for IDs, URLs, and tokens.
String? navivoxFirstStringFieldFromJson(
  Map<dynamic, dynamic> json,
  Iterable<String> names,
) {
  for (final name in names) {
    final exact = navivoxOptionalLiteralStringFromJson(json[name]);
    if (exact != null) return exact;
  }
  final normalizedNames = {
    for (final name in names) _navivoxNormalizeJsonFieldName(name),
  };
  for (final entry in json.entries) {
    if (!normalizedNames.contains(
      _navivoxNormalizeJsonFieldName('${entry.key}'),
    )) {
      continue;
    }
    final value = navivoxOptionalLiteralStringFromJson(entry.value);
    if (value != null) return value;
  }
  return null;
}

String _navivoxNormalizeJsonFieldName(String value) =>
    value.toLowerCase().replaceAll('_', '');

List<String> navivoxStringListFieldFromJson(
  Map<String, Object?> json,
  String key,
) {
  return navivoxStringListFromJson(json[key]);
}

/// Returns non-empty trimmed string values in their original order.
List<String> navivoxTrimmedStringList(Iterable<Object?> values) {
  return values
      .map((item) => item.toString().trim())
      .where((item) => item.isNotEmpty)
      .toList(growable: false);
}

/// Returns a string map with null/blank values removed and remaining values
/// trimmed. Useful for query params and wire request bodies that share Navivox
/// non-empty string field semantics.
Map<String, String> navivoxTrimmedStringFields(Map<String, Object?> values) {
  return {
    for (final entry in values.entries)
      if (entry.value case final value?)
        if (value.toString().trim().isNotEmpty)
          entry.key: value.toString().trim(),
  };
}

/// Returns a query-parameter map using the first non-empty value for each key.
///
/// This keeps copied URLs with duplicate blank parameters from erasing the
/// earlier value supplied by the producer.
Map<String, String> navivoxFirstNonBlankQueryParameterValues(
  Map<String, List<String>> queryParametersAll,
) {
  final result = <String, String>{};
  for (final entry in queryParametersAll.entries) {
    final value = navivoxFirstNonBlankQueryParameterValue(entry.value);
    if (value != null) result[entry.key] = value;
  }
  return result;
}

String? navivoxFirstNonBlankQueryParameterValue(List<String> values) {
  for (final value in values) {
    final text = navivoxOptionalLiteralStringFromJson(value);
    if (text != null) return text;
  }
  return null;
}

DateTime? navivoxDateTimeFromJson(Object? value) {
  final text = value?.toString().trim();
  if (text == null || text.isEmpty) return null;
  return DateTime.tryParse(text);
}

import 'dart:convert';

import '../../protocol/navivox_json.dart'
    show
        navivoxMapFieldFromJson,
        navivoxMapListFromJson,
        navivoxStringFieldFromJson,
        navivoxStringFromJson;

/// Decodes a gateway response body that must contain a JSON object.
Map<String, Object?> navivoxGatewayDecodeObject(String body) {
  final decoded = jsonDecode(body);
  if (decoded is! Map) {
    throw const FormatException('expected JSON object');
  }
  return Map<String, Object?>.from(decoded);
}

/// Converts a loose gateway JSON value into an object map when possible.
///
/// Adapter-provided maps must still obey the JSON object invariant that all
/// keys are strings. Malformed maps return `null` instead of leaking cast
/// exceptions through tolerant wire parsers.
Map<String, Object?>? navivoxGatewayOptionalObjectFromJson(Object? value) {
  if (value is! Map) return null;
  final object = <String, Object?>{};
  for (final entry in value.entries) {
    final key = entry.key;
    if (key is! String) return null;
    object[key] = entry.value;
  }
  return object;
}

/// Reads a gateway wire field as a raw string without trimming.
///
/// WebSocket event text fields preserve the gateway's existing coercion
/// semantics: any non-null value is converted with `toString()`, including
/// whitespace-only strings and numeric compatibility values.
String navivoxGatewayRawStringField(
  Map<String, Object?> json,
  String key, {
  String fallback = '',
}) {
  return json[key]?.toString() ?? fallback;
}

/// Reads an optional gateway wire field as a raw string without trimming.
String? navivoxGatewayOptionalRawStringField(
  Map<String, Object?> json,
  String key,
) {
  return json[key]?.toString();
}

/// Returns whether a loose gateway value contains non-empty text after trim.
///
/// Request builders and readiness checks intentionally share the same tolerant
/// string-presence contract: null and whitespace-only values are absent, while
/// non-string compatibility values are checked through their wire text form.
bool navivoxGatewayHasText(Object? value) {
  return value?.toString().trim().isNotEmpty ?? false;
}

/// Reads a literal boolean field from a decoded gateway response.
///
/// Gateway feature flags intentionally preserve strict wire semantics: only the
/// JSON boolean `true` is truthy, while strings or numeric aliases remain false.
bool navivoxGatewayBoolField(Map<String, Object?> json, String key) {
  return json[key] == true;
}

/// Reads a display string with a stable same-object fallback field.
///
/// Gateway profile-shaped responses often expose an optional display label that
/// falls back to the identity field when absent or blank. Centralizing that
/// contract keeps routing and voice views aligned without changing the tolerant
/// protocol string parsing semantics.
String navivoxGatewayStringFieldWithFallbackField(
  Map<String, Object?> json,
  String key,
  String fallbackKey,
) {
  return navivoxStringFromJson(
    json[key],
    fallback: navivoxStringFieldFromJson(json, fallbackKey),
  );
}

/// Reads a required JSON object field from a decoded gateway response.
Map<String, Object?> navivoxGatewayObjectField(
  Map<String, Object?> body,
  String key,
) {
  final object = navivoxGatewayOptionalObjectFromJson(body[key]);
  if (object == null) {
    throw FormatException('expected JSON object field $key');
  }
  return object;
}

/// Parses a nested gateway object field into a typed value.
///
/// Gateway response models use the protocol map-field contract for optional
/// nested objects: missing or malformed objects decode as an empty map, leaving
/// each typed parser responsible for its own defaults. This helper keeps that
/// object-field-to-value seam shared without changing wire tolerance.
T navivoxGatewayObjectFromField<T>(
  Map<String, Object?> json,
  String key,
  T Function(Map<String, Object?> json) fromJson,
) {
  return fromJson(navivoxMapFieldFromJson(json, key));
}

/// Parses a loose gateway JSON list into typed values.
///
/// Non-map values are ignored, matching the gateway wire contract used by the
/// protocol helpers, while the optional predicate keeps repeated non-empty ID
/// filtering close to the typed model being decoded.
List<T> navivoxGatewayObjectListFromJson<T>(
  Object? value,
  T Function(Map<String, Object?> json) fromJson, {
  bool Function(T item)? where,
}) {
  final items = navivoxMapListFromJson(value).map(fromJson);
  return (where == null ? items : items.where(where)).toList(growable: false);
}

/// Parses a loose gateway JSON list and keeps items whose selected text exists.
///
/// Several gateway collections tolerate partial rows but only expose rows with a
/// usable identity/key. This keeps that non-empty text filter shared with the
/// same tolerant string-presence contract used by request builders.
List<T> navivoxGatewayObjectListWhereHasText<T>(
  Object? value,
  T Function(Map<String, Object?> json) fromJson,
  Object? Function(T item) textOf,
) {
  return navivoxGatewayObjectListFromJson(
    value,
    fromJson,
    where: (item) => navivoxGatewayHasText(textOf(item)),
  );
}

/// Parses a loose gateway JSON object whose values are nested objects.
///
/// Non-map values are ignored so optional reference maps can tolerate forward
/// compatible wire payloads without each parser reimplementing the same loop.
Map<String, T> navivoxGatewayObjectValueMapFromJson<T>(
  Object? value,
  T Function(Map<String, Object?> json) fromJson,
) {
  if (value is! Map) return const {};
  final parsed = <String, T>{};
  for (final entry in value.entries) {
    final object = navivoxGatewayOptionalObjectFromJson(entry.value);
    if (object != null) {
      parsed[entry.key.toString()] = fromJson(object);
    }
  }
  return parsed;
}

